// Helper to generate logo URL from a website link
const getLogoUrl = (link: string): string => {
  try {
    const url = new URL(link);
    return `https://logo.clearbit.com/${url.hostname}`;
  } catch (error) {
    return 'https://via.placeholder.com/64';
  }
};

